import React, { useEffect, useState, useRef } from "react";
import axios from "axios";
import "./PriceList.css";

const API_URL = "http://localhost:7000/api/prices";
const CATEGORY_URL = "http://localhost:7000/api/categories";

export default function PriceList() {
  const [items, setItems] = useState([]);
  const [categories, setCategories] = useState([]);
  const [filtered, setFiltered] = useState([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedCategory, setSelectedCategory] = useState("all");
  const [priceFilter, setPriceFilter] = useState("all");
  const [selectedItems, setSelectedItems] = useState([]);
  const [selectAll, setSelectAll] = useState(false);
  const [form, setForm] = useState({
    name: "",
    category: "",
    description: "",
    basePrice: "",
    difference: "",
    validTill: "",
    file: null,
  });
  const [editId, setEditId] = useState(null);
  const [loading, setLoading] = useState(false);
  const [csvFile, setCsvFile] = useState(null);
  const [bulkUpdateFile, setBulkUpdateFile] = useState(null);
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 10;
  const csvInputRef = useRef();
  const bulkUpdateRef = useRef();

  useEffect(() => {
    fetchItems();
    fetchCategories();
  }, []);

  useEffect(() => {
    applyFilters();
  }, [searchTerm, selectedCategory, priceFilter, items]);

  const fetchItems = async () => {
    setLoading(true);
    try {
      const res = await axios.get(API_URL);
      if (res.data.success) {
        setItems(res.data.data);
        setFiltered(res.data.data);
      }
    } catch (err) {
      console.error("Error fetching items:", err);
    } finally {
      setLoading(false);
    }
  };

  const fetchCategories = async () => {
    try {
      const res = await axios.get(CATEGORY_URL);
      if (res.data.success) setCategories(res.data.categories);
    } catch (err) {
      console.error("Error fetching categories:", err);
    }
  };

  const applyFilters = () => {
    let temp = [...items];
    if (searchTerm.trim()) {
      temp = temp.filter((i) =>
        i.name.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }
    if (selectedCategory !== "all") {
      temp = temp.filter((i) => i.category?._id === selectedCategory);
    }
    if (priceFilter === "positive") temp = temp.filter((i) => i.difference > 0);
    else if (priceFilter === "negative") temp = temp.filter((i) => i.difference < 0);
    else if (priceFilter === "zero") temp = temp.filter((i) => i.difference === 0);
    setFiltered(temp);
  };

  const handleChange = (e) => {
    const { name, value, files } = e.target;
    if (files) setForm({ ...form, file: files[0] });
    else setForm({ ...form, [name]: value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      if (!form.name || !form.category || !form.basePrice) {
        alert("Name, category, and base price are required");
        setLoading(false);
        return;
      }

      const fd = new FormData();
      Object.keys(form).forEach((key) => {
        if (form[key]) fd.append(key, form[key]);
      });

      if (editId) await axios.put(`${API_URL}/${editId}`, fd);
      else await axios.post(API_URL, fd);

      setForm({
        name: "",
        category: "",
        description: "",
        basePrice: "",
        difference: "",
        validTill: "",
        file: null,
      });
      setEditId(null);
      fetchItems();
    } catch (err) {
      console.error("Save error:", err);
    } finally {
      setLoading(false);
    }
  };

  const handleEdit = (item) => {
    setForm({
      name: item.name,
      category: item.category?._id || "",
      description: item.description || "",
      basePrice: item.basePrice,
      difference: item.difference,
      validTill: item.validTill ? item.validTill.split("T")[0] : "",
      file: null,
    });
    setEditId(item._id);
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Delete this item?")) return;
    setLoading(true);
    try {
      await axios.delete(`${API_URL}/${id}`);
      fetchItems();
    } catch (err) {
      console.error("Delete error:", err);
    } finally {
      setLoading(false);
    }
  };

  const handleBulkDelete = async () => {
    if (selectedItems.length === 0) return alert("No items selected");
    if (!window.confirm(`Delete ${selectedItems.length} items?`)) return;
    setLoading(true);
    try {
      await Promise.all(selectedItems.map((id) => axios.delete(`${API_URL}/${id}`)));
      alert("Deleted successfully!");
      setSelectedItems([]);
      setSelectAll(false);
      fetchItems();
    } catch (err) {
      console.error("Bulk delete error:", err);
    } finally {
      setLoading(false);
    }
  };

  const toggleSelectAll = (checked) => {
    setSelectAll(checked);
    if (checked) setSelectedItems(filtered.map((i) => i._id));
    else setSelectedItems([]);
  };

  const toggleSelectItem = (id) => {
    setSelectedItems((prev) =>
      prev.includes(id) ? prev.filter((i) => i !== id) : [...prev, id]
    );
  };

  // CSV Import
  const handleCsvSelect = (e) => setCsvFile(e.target.files[0]);

  const handleImportCsv = async () => {
    if (!csvFile) return alert("Choose a CSV file first");
    const fd = new FormData();
    fd.append("file", csvFile);
    setLoading(true);
    try {
      const res = await axios.post(`${API_URL}/import`, fd, {
        headers: { "Content-Type": "multipart/form-data" },
      });
      if (res.data.success) {
        alert(`Imported ${res.data.inserted || 0} items`);
        fetchItems();
        setCsvFile(null);
        csvInputRef.current.value = "";
      } else alert("Import failed, check file format");
    } catch (err) {
      console.error("Import error:", err);
    } finally {
      setLoading(false);
    }
  };

  // CSV Export
  const handleExportCsv = async () => {
    try {
      setLoading(true);
      const res = await axios.get(`${API_URL}/export`, { responseType: "blob" });
      const blob = new Blob([res.data], { type: "text/csv;charset=utf-8;" });
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url;
      a.download = `prices_export_${Date.now()}.csv`;
      document.body.appendChild(a);
      a.click();
      a.remove();
    } catch (err) {
      console.error("Export error:", err);
    } finally {
      setLoading(false);
    }
  };

  // Bulk Update via CSV
  const handleBulkUpdateSelect = (e) => setBulkUpdateFile(e.target.files[0]);

  const handleBulkUpdate = async () => {
    if (!bulkUpdateFile) return alert("Choose a bulk update CSV file first");
    const fd = new FormData();
    fd.append("file", bulkUpdateFile);
    setLoading(true);
    try {
      const res = await axios.post(`${API_URL}/bulkupdate`, fd, {
        headers: { "Content-Type": "multipart/form-data" },
      });
      if (res.data.success) {
        alert(`Updated ${res.data.updated || 0} items`);
        fetchItems();
        setBulkUpdateFile(null);
        bulkUpdateRef.current.value = "";
      } else alert("Update failed");
    } catch (err) {
      console.error("Bulk update error:", err);
    } finally {
      setLoading(false);
    }
  };

  // Pagination logic
  const totalPages = Math.ceil(filtered.length / itemsPerPage);
  const paginatedItems = filtered.slice(
    (currentPage - 1) * itemsPerPage,
    currentPage * itemsPerPage
  );

  const handleNextPage = () => {
    if (currentPage < totalPages) setCurrentPage((prev) => prev + 1);
  };
  const handlePrevPage = () => {
    if (currentPage > 1) setCurrentPage((prev) => prev - 1);
  };

  return (
    <div className="price-container">
      <div className="header-section">
        <h1>💰 Price Management</h1>
        <p>Search, filter, import, export, and bulk update product prices</p>
      </div>

      {/* CSV Controls */}
      <div className="csv-controls">
        <div className="csv-actions">
          <input type="file" accept=".csv,text/csv" ref={csvInputRef} onChange={handleCsvSelect} />
          <button className="btn small" onClick={handleImportCsv}>📥 Import CSV</button>
          <button className="btn small" onClick={handleExportCsv}>📤 Export CSV</button>
          <input type="file" accept=".csv,text/csv" ref={bulkUpdateRef} onChange={handleBulkUpdateSelect} />
          <button className="btn small secondary" onClick={handleBulkUpdate}>🧾 Bulk Update CSV</button>
        </div>
      </div>

      {/* Search & Filter Bar */}
      <div className="search-filter-bar">
        <div className="search-box">
          <span className="search-icon">🔍</span>
          <input
            type="text"
            placeholder="Search by name..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <select value={selectedCategory} onChange={(e) => setSelectedCategory(e.target.value)}>
          <option value="all">All Categories</option>
          {categories.map((cat) => (
            <option key={cat._id} value={cat._id}>{cat.name}</option>
          ))}
        </select>

        <select value={priceFilter} onChange={(e) => setPriceFilter(e.target.value)}>
          <option value="all">All Differences</option>
          <option value="positive">Positive (+)</option>
          <option value="negative">Negative (-)</option>
          <option value="zero">Zero (0)</option>
        </select>

        {selectedItems.length > 0 && (
          <button className="btn delete" onClick={handleBulkDelete}>
            🗑 Delete Selected ({selectedItems.length})
          </button>
        )}
      </div>

      {/* Form Section */}
      <form className="price-form" onSubmit={handleSubmit}>
        <input name="name" value={form.name} onChange={handleChange} placeholder="Product Name *" required />
        <select name="category" value={form.category} onChange={handleChange} required>
          <option value="">Select Category</option>
          {categories.map((cat) => (
            <option key={cat._id} value={cat._id}>{cat.name}</option>
          ))}
        </select>
        <input type="number" name="basePrice" value={form.basePrice} onChange={handleChange} placeholder="Base Price *" required />
        <input type="number" name="difference" value={form.difference} onChange={handleChange} placeholder="Difference" />
        <input type="date" name="validTill" value={form.validTill} onChange={handleChange} />
        <input type="file" name="file" onChange={handleChange} accept="image/*" />
        <textarea name="description" value={form.description} onChange={handleChange} placeholder="Description..." />
        <button type="submit" className="btn primary">{editId ? "Update Price" : "Add Price"}</button>
      </form>

      {/* Table Section */}
      <div className="table-card">
        {loading ? (
          <div className="loader">Loading...</div>
        ) : paginatedItems.length === 0 ? (
          <p className="empty">No items found.</p>
        ) : (
          <>
            <table>
              <thead>
                <tr>
                  <th><input type="checkbox" checked={selectAll} onChange={(e) => toggleSelectAll(e.target.checked)} /></th>
                  <th>Image</th>
                  <th>Name</th>
                  <th>Category</th>
                  <th>Base Price</th>
                  <th>Diff</th>
                  <th>Final</th>
                  <th>Valid Till</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {paginatedItems.map((item) => (
                  <tr key={item._id}>
                    <td><input type="checkbox" checked={selectedItems.includes(item._id)} onChange={() => toggleSelectItem(item._id)} /></td>
                    <td>{item.image ? <img src={item.image} alt={item.name} /> : "No Img"}</td>
                    <td>{item.name}</td>
                    <td>{item.category?.name || "N/A"}</td>
                    <td>₹{item.basePrice}</td>
                    <td>{item.difference}</td>
                    <td>₹{item.basePrice + (item.difference || 0)}</td>
                    <td>{item.validTill ? new Date(item.validTill).toLocaleDateString("en-IN") : "-"}</td>
                    <td>
                      <button className="btn edit" onClick={() => handleEdit(item)}>Edit</button>
                      <button className="btn delete" onClick={() => handleDelete(item._id)}>Delete</button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>

            {/* Pagination */}
            <div className="pagination">
              <button onClick={handlePrevPage} disabled={currentPage === 1}>⬅ Prev</button>
              <span>Page {currentPage} of {totalPages}</span>
              <button onClick={handleNextPage} disabled={currentPage === totalPages}>Next ➡</button>
            </div>
          </>
        )}
      </div>
    </div>
  );
}
